head.script:
tailwind.config = {
  theme: {
    extend: {
      fontFamily: {
        sans: ['"Plus Jakarta Sans"', 'sans-serif'],
        display: ['"Plus Jakarta Sans"', 'sans-serif'],
      }
    }
  }
}

head.b:skin:
body { font-family: 'Plus Jakarta Sans', sans-serif; background-color: #f8fafc; color: #0f172a; overflow-x: hidden; }
.glass-morphism { background: rgba(255,255,255,0.8); backdrop-filter: blur(16px); }
.text-gradient { background: linear-gradient(to right, #0891b2, #6366f1, #e11d48); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.bg-gradient-brand { background: linear-gradient(135deg, #0891b2 0%, #4f46e5 100%); }
.widget { outline: none; margin: 0; }
.section, .widget, .widget-content { margin: 0; padding: 0; }

body.script:
lucide.createIcons();
// Navbar scroll effect
window.addEventListener('scroll', () => {
  const nav = document.getElementById('navbar');
  if (window.scrollY > 20) {
    nav.classList.add('bg-white/80', 'backdrop-blur-xl', 'border-b', 'py-3');
    nav.classList.remove('bg-transparent', 'py-6');
  } else {
    nav.classList.remove('bg-white/80', 'backdrop-blur-xl', 'border-b', 'py-3');
    nav.classList.add('bg-transparent', 'py-6');
  }
});
